import './globals.css';
import { ThemeProvider } from './components/theme-provider';

export const metadata = {
  title: 'thepopebot',
  description: 'AI Agent',
};

export default function RootLayout({ children }) {
  return (
    <html lang="en" suppressHydrationWarning>
      <body className="min-h-screen bg-background text-foreground antialiased">
        <ThemeProvider>
          {children}
        </ThemeProvider>
      </body>
    </html>
  );
}

@import "tailwindcss";
@import "streamdown/styles.css";
@source "../node_modules/thepopebot/lib/**/*.{js,jsx}";
@source "../node_modules/streamdown/dist/**/*.js";

:root {
  --background: #ffffff;
  --foreground: #171717;
  --primary: #171717;
  --primary-foreground: #ffffff;
  --muted: #f5f5f5;
  --muted-foreground: #737373;
  --border: #e5e5e5;
  --input: #f5f5f5;
  --ring: #171717;
  --destructive: #dc2626;
}

.dark {
  --background: #0a0a0a;
  --foreground: #ededed;
  --primary: #ededed;
  --primary-foreground: #0a0a0a;
  --muted: #171717;
  --muted-foreground: #a3a3a3;
  --border: #262626;
  --input: #171717;
  --ring: #ededed;
  --destructive: #ef4444;
}

@theme inline {
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --color-primary: var(--primary);
  --color-primary-foreground: var(--primary-foreground);
  --color-muted: var(--muted);
  --color-muted-foreground: var(--muted-foreground);
  --color-border: var(--border);
  --color-input: var(--input);
  --color-ring: var(--ring);
  --color-destructive: var(--destructive);
  --text-xs: 0.8125rem;
  --text-xs--line-height: 1.125rem;
  --text-sm: 1rem;
  --text-sm--line-height: 1.5rem;
  --font-sans: system-ui, -apple-system, sans-serif;
  --font-mono: ui-monospace, 'Cascadia Code', 'Source Code Pro', monospace;
  --radius-sm: 0.375rem;
  --radius-md: 0.5rem;
  --radius-lg: 0.75rem;
}

/* Scrollbar styling */
.scrollbar-thin {
  scrollbar-width: thin;
  scrollbar-color: var(--border) transparent;
}

.scrollbar-thin::-webkit-scrollbar {
  width: 6px;
}

.scrollbar-thin::-webkit-scrollbar-track {
  background: transparent;
}

.scrollbar-thin::-webkit-scrollbar-thumb {
  background-color: var(--border);
  border-radius: 3px;
}

/* Code block horizontal scroll — target the pre (code-block-body), not the
   outer wrapper which needs overflow-hidden for border-radius clipping */
[data-streamdown="code-block-body"] {
  overflow-x: auto !important;
}

[data-streamdown="code-block-body"]::-webkit-scrollbar {
  height: 6px;
}

[data-streamdown="code-block-body"]::-webkit-scrollbar-track {
  background: transparent;
}

[data-streamdown="code-block-body"]::-webkit-scrollbar-thumb {
  background-color: var(--border);
  border-radius: 3px;
}
